#!/usr/bin/env python3
"""
Export protein-ligand complex as PDB for FragGen GUI.

Combines the receptor PDB with a docked ligand pose from an SDF file.
"""

import argparse
import gzip
import os
import sys
from pathlib import Path

try:
    from rdkit import Chem
    from rdkit.Chem import AllChem
    HAS_RDKIT = True
except ImportError:
    HAS_RDKIT = False


def read_receptor_pdb(pdb_path):
    """Read receptor PDB and return lines (excluding END)."""
    lines = []
    with open(pdb_path, 'r') as f:
        for line in f:
            # Skip END records - we'll add our own at the end
            if line.startswith('END'):
                continue
            lines.append(line)
    return lines


def get_ligand_from_sdf(sdf_path, pose_index=0):
    """Extract a specific pose from docked SDF and convert to PDB format."""
    if not HAS_RDKIT:
        raise RuntimeError("RDKit is required for complex PDB export")

    # Read SDF file
    if sdf_path.endswith('.gz'):
        with gzip.open(sdf_path, 'rt') as f:
            suppl = Chem.ForwardSDMolSupplier(f)
            mols = list(suppl)
    else:
        suppl = Chem.SDMolSupplier(sdf_path)
        mols = list(suppl)

    if pose_index >= len(mols) or mols[pose_index] is None:
        raise ValueError(f"Pose {pose_index} not found in {sdf_path}")

    mol = mols[pose_index]

    # Get ligand name from filename
    ligand_name = Path(sdf_path).stem.replace('_docked', '')[:3].upper()
    if not ligand_name:
        ligand_name = 'LIG'

    # Convert to PDB block
    pdb_block = Chem.MolToPDBBlock(mol)

    # Modify the PDB lines to use HETATM and proper residue naming
    modified_lines = []
    atom_serial = 1

    for line in pdb_block.split('\n'):
        if line.startswith('ATOM') or line.startswith('HETATM'):
            # Convert to HETATM format with ligand residue name
            atom_name = line[12:16]
            x = line[30:38]
            y = line[38:46]
            z = line[46:54]
            element = line[76:78].strip() if len(line) > 76 else atom_name[0]

            # Format: HETATM serial name resName chain resSeq x y z occupancy tempFactor element
            new_line = f"HETATM{atom_serial:5d} {atom_name} {ligand_name:3s} L   1    {x}{y}{z}  1.00  0.00          {element:>2s}"
            modified_lines.append(new_line)
            atom_serial += 1
        elif line.startswith('CONECT'):
            modified_lines.append(line)

    return modified_lines


def main():
    parser = argparse.ArgumentParser(description='Export protein-ligand complex PDB')
    parser.add_argument('--receptor', required=True, help='Receptor PDB file')
    parser.add_argument('--ligand_sdf', required=True, help='Docked ligand SDF file')
    parser.add_argument('--pose', type=int, default=0, help='Pose index (0-based, default: 0 = best pose)')
    parser.add_argument('--output', required=True, help='Output complex PDB file')
    args = parser.parse_args()

    if not os.path.exists(args.receptor):
        print(f'ERROR: Receptor not found: {args.receptor}', file=sys.stderr)
        sys.exit(1)

    if not os.path.exists(args.ligand_sdf):
        print(f'ERROR: Ligand SDF not found: {args.ligand_sdf}', file=sys.stderr)
        sys.exit(1)

    if not HAS_RDKIT:
        print('ERROR: RDKit is required for complex PDB export', file=sys.stderr)
        sys.exit(1)

    try:
        # Read receptor
        receptor_lines = read_receptor_pdb(args.receptor)

        # Get ligand PDB lines
        ligand_lines = get_ligand_from_sdf(args.ligand_sdf, args.pose)

        # Write combined PDB
        ligand_name = Path(args.ligand_sdf).stem.replace('_docked', '')

        with open(args.output, 'w') as f:
            f.write(f"REMARK  Protein-ligand complex generated by FragGen\n")
            f.write(f"REMARK  Receptor: {os.path.basename(args.receptor)}\n")
            f.write(f"REMARK  Ligand: {ligand_name} (pose {args.pose + 1})\n")

            # Write receptor
            for line in receptor_lines:
                f.write(line)

            # Write TER between receptor and ligand
            f.write("TER\n")

            # Write ligand
            for line in ligand_lines:
                f.write(line + '\n')

            f.write("END\n")

        print(f'SUCCESS: Complex written to {args.output}')

    except Exception as e:
        print(f'ERROR: {str(e)}', file=sys.stderr)
        sys.exit(1)


if __name__ == '__main__':
    main()
